INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_greeting_01', 'meet', 'see', NULL, '(처음) 만나다', '(아는 사람을) 만나다', NULL, 'meet는 보통 처음 만남을 뜻하고, see는 이미 아는 사람과의 만남을 뜻해요.', 'Nice to meet you!', 'Nice to see you again!', NULL, '"Nice to meet you"는 처음 만날 때만, "Nice to see you"는 재회 시 사용해요.', 'B1', 'greeting', 1, 'meeting people handshake', 1),
('nuc_greeting_02', 'say', 'tell', NULL, '말하다 (내용 중심)', '말하다 (상대 중심)', NULL, 'say는 말한 내용에 초점을 두고, tell은 누구에게 말하는지 상대방에 초점을 둬요.', 'She said goodbye.', 'She told me to leave.', NULL, '"Tell me" / "Say hello"처럼 tell 뒤에는 사람, say 뒤에는 내용이 와요.', 'B1', 'greeting', 2, 'conversation talking', 2),
('nuc_greeting_03', 'speak', 'talk', NULL, '말하다 (공식적)', '말하다 (대화하다)', NULL, 'speak는 좀 더 공식적이거나 일방적인 말하기, talk는 서로 주고받는 대화를 강조해요.', 'May I speak to the manager?', 'Can we talk for a moment?', NULL, '공식 자리에서는 speak, 편한 대화에서는 talk가 자연스러워요.', 'B1', 'greeting', 1, 'speaking conversation formal', 3),
('nuc_greeting_04', 'greet', 'welcome', NULL, '인사하다', '환영하다', NULL, 'greet는 만났을 때 인사하는 행위, welcome은 상대를 따뜻이 받아들이는 행위예요.', 'She greeted every guest at the door.', 'Welcome to our home!', NULL, 'greet는 짧은 인사, welcome은 공간이나 상황에 받아들인다는 뉘앙스가 있어요.', 'B1', 'greeting', 2, 'welcome door arrival', 4),
('nuc_greeting_05', 'introduce', 'present', NULL, '소개하다', '발표하다 / 소개하다', NULL, 'introduce는 사람을 서로 알게 해주는 것, present는 좀 더 격식 있는 자리에서 소개·발표하는 것이에요.', 'Let me introduce my colleague.', 'Allow me to present our new director.', NULL, '비즈니스 자리에서는 present, 일상 자리에서는 introduce가 더 자연스러워요.', 'B2', 'greeting', 1, 'introduction formal meeting', 5),
('nuc_greeting_06', 'farewell', 'goodbye', NULL, '작별 (격식)', '안녕히 가세요 (일상)', NULL, 'farewell은 격식 있거나 오랜 이별 상황, goodbye는 일상적인 작별 인사에 써요.', 'It was a bittersweet farewell.', 'Goodbye! See you tomorrow.', NULL, 'farewell은 감정적·격식적 뉘앙스, goodbye는 가볍게 쓸 수 있어요.', 'B2', 'greeting', 2, 'goodbye farewell parting', 6),
('nuc_greeting_07', 'acquaintance', 'friend', NULL, '지인', '친구', NULL, 'acquaintance는 알고 있지만 친밀하지 않은 사람, friend는 친밀한 관계를 나타내요.', 'He''s just an acquaintance from work.', 'She''s my best friend.', NULL, '한국어 "아는 사람"은 acquaintance에 가깝고, 진짜 친한 사이가 friend예요.', 'B1', 'greeting', 2, 'friends acquaintance social', 7),
('nuc_greeting_08', 'familiar', 'intimate', NULL, '익숙한 / 친숙한', '친밀한 / 각별한', NULL, 'familiar는 알고 있어 낯설지 않은 느낌, intimate는 감정적으로 매우 가까운 관계를 뜻해요.', 'Her voice sounds familiar.', 'They have an intimate friendship.', NULL, 'familiar는 인지적 친숙함, intimate는 감정적 친밀감을 강조해요.', 'B2', 'greeting', 2, 'familiarity friendship close', 8),
('nuc_greeting_09', 'formal', 'polite', NULL, '격식 있는', '정중한', NULL, 'formal은 형식과 규칙을 따르는 것, polite는 예의 바른 태도 자체를 뜻해요.', 'The ceremony was very formal.', 'He was polite to everyone.', NULL, 'formal은 복장·행사·언어 형식을 가리키고, polite는 행동 예절을 가리켜요.', 'B2', 'greeting', 1, 'formal polite manners', 9),
('nuc_greeting_10', 'chat', 'converse', NULL, '잡담하다', '대화하다 (격식)', NULL, 'chat은 가벼운 수다, converse는 좀 더 진지하거나 격식 있는 대화를 뜻해요.', 'We chatted about the weather.', 'They conversed in fluent French.', NULL, 'chat은 일상·온라인 대화, converse는 글·격식 문맥에서 자주 보여요.', 'B2', 'greeting', 2, 'chatting conversation casual', 10),
('nuc_greeting_11', 'address', 'call', NULL, '~라고 부르다 (호칭)', '~라고 부르다 (이름)', NULL, 'address는 격식 있는 호칭 방식, call은 이름이나 별명으로 부르는 일상적 표현이에요.', 'Please address me as Dr. Kim.', 'Just call me Mike.', NULL, '공식 자리에서는 address, 편한 자리에서는 call을 써요.', 'C1', 'greeting', 1, 'name title address formal', 11),
('nuc_greeting_12', 'cordial', 'warm', NULL, '정중하고 친절한', '따뜻한', NULL, 'cordial은 격식 있으면서도 친절한 뉘앙스, warm은 감정적으로 따뜻한 느낌을 줘요.', 'The host gave a cordial welcome.', 'She has a warm personality.', NULL, 'cordial은 비즈니스·공식 문맥, warm은 개인 감정 표현에 자주 써요.', 'C1', 'greeting', 2, 'warm cordial welcome hospitality', 12),
('nuc_greeting_13', 'salutation', 'greeting', NULL, '(서신의) 인사말', '인사 / 인사하기', NULL, 'salutation은 편지·이메일 첫머리 인사말을 특별히 가리키고, greeting은 모든 종류의 인사를 포함해요.', 'The salutation in the email read "Dear Sir."', 'A simple greeting can brighten someone''s day.', NULL, 'salutation은 글쓰기에서, greeting은 구어·문어 모두에서 쓰여요.', 'C2', 'greeting', 1, 'letter salutation formal writing', 13);
INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_emotion_01', 'happy', 'glad', 'content', '행복한', '기쁜 (순간)', '만족한', 'happy는 전반적 행복감, glad는 특정 일에 대한 즉각적 기쁨, content는 조용한 만족감이에요.', 'She feels happy every morning.', 'I''m glad you came.', 'He was content with his simple life.', 'glad는 "I''m glad to hear that"처럼 감사·안도 상황에 자주 써요.', 'B1', 'emotion', 1, 'happiness joy contentment', 1),
('nuc_emotion_02', 'sad', 'upset', NULL, '슬픈', '속상한 / 화난', NULL, 'sad는 슬픔의 감정, upset는 슬픔뿐 아니라 화가 나거나 속상한 복합 감정이에요.', 'She felt sad after the movie.', 'He was upset about the cancellation.', NULL, 'upset은 감정이 흔들린 상태를 폭넓게 가리켜 sad보다 강도가 세요.', 'B1', 'emotion', 1, 'sadness emotion feeling', 2),
('nuc_emotion_03', 'angry', 'annoyed', 'furious', '화난', '짜증난', '격노한', 'annoyed는 가벼운 짜증, angry는 그보다 강한 화남, furious는 매우 격한 분노예요.', 'She was angry at the delay.', 'He was annoyed by the noise.', 'She was furious when she found out the truth.', '강도 순서: annoyed < angry < furious로 기억하세요.', 'B1', 'emotion', 2, 'anger frustration emotion', 3),
('nuc_emotion_04', 'afraid', 'scared', 'terrified', '두려운', '무서운', '공포에 질린', 'afraid는 다소 격식 있는 표현, scared는 일상적으로 자주 쓰고, terrified는 극심한 공포예요.', 'She is afraid of the dark.', 'The dog scared me.', 'He was terrified by the explosion.', '강도 순서: afraid ≈ scared < terrified. 일상 대화에서는 scared가 가장 자연스러워요.', 'B1', 'emotion', 2, 'fear scared emotion dark', 4),
('nuc_emotion_05', 'excited', 'enthusiastic', NULL, '신이 난', '열정적인', NULL, 'excited는 특정 사건에 대한 흥분, enthusiastic은 어떤 일에 대한 지속적인 열정을 뜻해요.', 'She was excited about the trip.', 'He is enthusiastic about teaching.', NULL, 'excited는 순간적 감정, enthusiastic은 지속적 태도를 나타내요.', 'B2', 'emotion', 1, 'excitement enthusiasm energy', 5),
('nuc_emotion_06', 'embarrassed', 'ashamed', NULL, '당황한 / 부끄러운', '수치스러운', NULL, 'embarrassed는 사회적 상황에서 느끼는 부끄러움, ashamed는 도덕적 잘못에서 오는 수치심이에요.', 'I was embarrassed when I forgot her name.', 'He was ashamed of his past behavior.', NULL, 'embarrassed는 실수, ashamed는 도덕·가치 위반과 관련돼요.', 'B2', 'emotion', 1, 'embarrassment shame emotion', 6),
('nuc_emotion_07', 'worried', 'anxious', NULL, '걱정하는', '불안한', NULL, 'worried는 특정 문제에 대한 걱정, anxious는 막연한 불안 또는 간절히 원하는 느낌도 포함해요.', 'I''m worried about the exam results.', 'She was anxious to please her boss.', NULL, 'anxious는 "몹시 ~하고 싶어"라는 뜻으로도 쓰여요 (예: anxious to succeed).', 'B2', 'emotion', 2, 'worry anxiety stress', 7),
('nuc_emotion_08', 'lonely', 'alone', NULL, '외로운', '혼자인', NULL, 'alone은 혼자 있다는 사실, lonely는 혼자여서 외롭다는 감정이에요.', 'She felt lonely in the crowd.', 'He lives alone but is not lonely.', NULL, '혼자(alone)라고 외로운(lonely) 건 아니에요 — 둘을 구분하는 게 중요해요.', 'B1', 'emotion', 1, 'loneliness solitude alone', 8),
('nuc_emotion_09', 'jealous', 'envious', NULL, '질투하는', '부러워하는', NULL, 'jealous는 자기 것을 빼앗길까 두려운 감정, envious는 남의 것을 갖고 싶은 감정이에요.', 'He felt jealous when she talked to other men.', 'I''m envious of her talent.', NULL, 'jealous는 관계, envious는 소유·능력에 관한 감정이에요.', 'B2', 'emotion', 2, 'jealousy envy emotion relationship', 9),
('nuc_emotion_10', 'disappointed', 'discouraged', NULL, '실망한', '낙담한', NULL, 'disappointed는 기대가 충족되지 않은 실망, discouraged는 의욕을 잃은 낙담이에요.', 'She was disappointed by the result.', 'He felt discouraged after failing again.', NULL, 'disappointed는 결과에 대한 반응, discouraged는 계속하려는 의지가 꺾인 것이에요.', 'B2', 'emotion', 1, 'disappointment discouragement failure', 10),
('nuc_emotion_11', 'sympathy', 'empathy', NULL, '동정', '공감', NULL, 'sympathy는 타인의 고통을 가엽게 여기는 것, empathy는 그 감정을 함께 느끼는 것이에요.', 'He expressed sympathy for the victims.', 'Good therapists show empathy toward clients.', NULL, 'empathy가 더 깊은 정서적 연결을 뜻해요 — 상담·리더십 문맥에서 중요해요.', 'C1', 'emotion', 1, 'empathy sympathy compassion', 11),
('nuc_emotion_12', 'melancholy', 'sorrow', NULL, '우울한 감성', '슬픔 / 비탄', NULL, 'melancholy는 이유 없이 스미는 우울한 기분, sorrow는 뚜렷한 이유가 있는 깊은 슬픔이에요.', 'Autumn fills me with a quiet melancholy.', 'His sorrow after the loss was immense.', NULL, 'melancholy는 시적 문맥에 자주 쓰이고, sorrow는 상실에 대한 비탄이에요.', 'C1', 'emotion', 2, 'melancholy sorrow sadness autumn', 12),
('nuc_emotion_13', 'elated', 'euphoric', NULL, '기분이 들뜬', '황홀한 / 극도로 행복한', NULL, 'elated는 매우 기쁘고 들뜬 상태, euphoric은 거의 비현실적으로 느껴질 만큼 황홀한 상태예요.', 'She was elated by the good news.', 'He felt euphoric after winning the championship.', NULL, '강도 순서: happy < elated < euphoric. euphoric은 극적인 상황에 써요.', 'C2', 'emotion', 1, 'elation euphoria happiness intense', 13);
INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_weather_01', 'rain', 'drizzle', NULL, '비', '이슬비 / 보슬비', NULL, 'rain은 일반적인 비, drizzle은 매우 가늘고 약하게 내리는 비예요.', 'It started to rain heavily.', 'A light drizzle made the street shiny.', NULL, 'drizzle은 우산 없이도 걸을 수 있을 만큼 약한 비예요.', 'B1', 'weather', 1, 'rain drizzle wet street', 1),
('nuc_weather_02', 'wind', 'breeze', 'gust', '바람', '산들바람', '돌풍', 'breeze는 부드럽고 상쾌한 바람, wind는 일반적 바람, gust는 갑자기 세게 부는 돌풍이에요.', 'A cold wind blew all day.', 'A gentle breeze cooled the afternoon.', 'A sudden gust knocked over the umbrella.', '강도 순서: breeze < wind < gust. 날씨 예보에서 gust를 자주 들어요.', 'B1', 'weather', 1, 'wind breeze gust weather', 2),
('nuc_weather_03', 'cloudy', 'overcast', NULL, '흐린', '완전히 흐린', NULL, 'cloudy는 구름이 일부 있는 상태, overcast는 하늘 전체가 구름으로 덮인 상태예요.', 'It was partly cloudy this morning.', 'The sky was completely overcast by noon.', NULL, '예보에서 overcast는 종일 구름이 가득 낀 날을 뜻해요.', 'B1', 'weather', 2, 'cloudy overcast sky grey', 3),
('nuc_weather_04', 'hot', 'warm', NULL, '더운', '따뜻한', NULL, 'warm은 적당히 따뜻한 기분 좋은 날씨, hot은 불쾌할 만큼 더운 날씨예요.', 'It was so hot that we stayed indoors.', 'The weather was warm and pleasant.', NULL, '기분 좋은 날씨에는 warm, 불쾌하게 더울 때는 hot을 쓰면 정확해요.', 'B1', 'weather', 2, 'hot warm temperature summer', 4),
('nuc_weather_05', 'cold', 'chilly', 'freezing', '추운', '쌀쌀한', '매우 추운', 'chilly는 약간 쌀쌀한 정도, cold는 춥다는 일반적 표현, freezing은 매우 심하게 춥거나 과장 표현이에요.', 'It''s cold enough to wear a coat.', 'It''s a bit chilly — bring a jacket.', 'It''s freezing outside today!', '강도 순서: chilly < cold < freezing. freezing은 과장 표현으로도 써요.', 'B1', 'weather', 2, 'cold chilly freezing winter', 5),
('nuc_weather_06', 'storm', 'shower', NULL, '폭풍', '소나기', NULL, 'shower는 짧고 갑작스러운 비, storm은 강풍이나 번개를 동반한 거센 날씨예요.', 'The storm caused widespread damage.', 'We got caught in a brief shower.', NULL, '예보에서 "scattered showers"는 곳곳에 소나기, "storm warning"은 강한 폭풍 경보예요.', 'B2', 'weather', 1, 'storm shower rain weather', 6),
('nuc_weather_07', 'fog', 'mist', NULL, '짙은 안개', '엷은 안개 / 안개비', NULL, 'mist는 옅고 부드러운 안개, fog는 더 짙어 시야를 심하게 가리는 안개예요.', 'Dense fog closed the airport.', 'A light mist hung over the lake.', NULL, '운전·항공 예보에서 fog는 visibility(가시거리) 문제를 일으켜요.', 'B2', 'weather', 2, 'fog mist visibility morning', 7),
('nuc_weather_08', 'humid', 'muggy', NULL, '습한', '후텁지근한', NULL, 'humid는 습도가 높은 상태, muggy는 습하고 더워서 불쾌한 상태예요.', 'Seoul summers are very humid.', 'It was so muggy that we could barely breathe.', NULL, 'muggy는 humid보다 불쾌함이 추가된 표현이에요.', 'B2', 'weather', 1, 'humid muggy summer heat', 8),
('nuc_weather_09', 'lightning', 'thunder', NULL, '번개', '천둥', NULL, 'lightning은 눈에 보이는 번쩍임, thunder는 귀에 들리는 천둥소리예요.', 'Lightning struck the tree.', 'We heard thunder in the distance.', NULL, '번개(lightning)가 먼저 보이고, 천둥(thunder)이 나중에 들려요.', 'B2', 'weather', 2, 'lightning thunder storm', 9),
('nuc_weather_10', 'forecast', 'predict', NULL, '예보하다', '예측하다', NULL, 'forecast는 날씨·경제 등 전문적 예측, predict는 다양한 상황에서의 예측을 뜻해요.', 'The forecast calls for snow tomorrow.', 'Scientists predicted the weather would change.', NULL, 'weather forecast는 공식 기상 예보, predict는 더 넓은 문맥에서 써요.', 'B2', 'weather', 1, 'forecast predict weather report', 10),
('nuc_weather_11', 'blizzard', 'snowstorm', NULL, '눈보라', '폭설', NULL, 'snowstorm은 폭설을 동반한 폭풍, blizzard는 강풍과 폭설이 함께하는 더 극심한 눈보라예요.', 'The blizzard shut down the entire city.', 'A sudden snowstorm surprised drivers.', NULL, 'blizzard는 공식 기상 용어로 특정 기준(풍속·가시거리)을 충족해야 해요.', 'C1', 'weather', 1, 'blizzard snowstorm winter storm', 11),
('nuc_weather_12', 'temperate', 'mild', NULL, '온화한 (기후)', '온화한 (날씨)', NULL, 'mild는 특정 날이 온화하다는 표현, temperate는 기후 유형 자체를 가리켜요.', 'Korea has a temperate climate.', 'We had a mild winter this year.', NULL, 'climate is temperate(기후), today is mild(날씨)처럼 스케일이 달라요.', 'C1', 'weather', 2, 'temperate mild climate zone', 12),
('nuc_weather_13', 'arid', 'drought', NULL, '건조한 (지형)', '가뭄', NULL, 'arid는 강수량이 매우 적은 건조한 기후·지역, drought는 비정상적으로 비가 안 오는 기간이에요.', 'The Sahara is an arid region.', 'The drought lasted for three years.', NULL, 'arid는 형용사(지역·기후), drought는 명사(기간·사건)로 써요.', 'C2', 'weather', 1, 'arid drought desert dry', 13);
INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_shopping_01', 'buy', 'purchase', NULL, '사다 (일상)', '구매하다 (격식)', NULL, 'buy는 일상 대화에서 쓰는 표현, purchase는 더 격식 있는 서면이나 공식 상황에서 써요.', 'I''m going to buy a new jacket.', 'Please purchase tickets online.', NULL, 'purchase는 계약서·영수증·공식 안내문에서 자주 보여요.', 'B1', 'shopping', 1, 'shopping buying retail store', 1),
('nuc_shopping_02', 'cheap', 'inexpensive', NULL, '싼 (부정적)', '저렴한 (중립)', NULL, 'cheap은 가격이 낮지만 품질도 낮다는 부정적 뉘앙스가 있고, inexpensive는 중립적으로 저렴하다는 뜻이에요.', 'This bag looks really cheap.', 'This bag is inexpensive but well-made.', NULL, '품질을 낮게 보이지 않게 하려면 cheap 대신 inexpensive나 affordable을 써요.', 'B1', 'shopping', 1, 'price cheap quality value', 2),
('nuc_shopping_03', 'discount', 'sale', NULL, '할인', '세일', NULL, 'discount는 정가에서 깎아주는 것, sale은 특정 기간 여러 상품을 할인 판매하는 행사예요.', 'Can I get a discount on this item?', 'The store is having a big sale this weekend.', NULL, '"on sale"은 할인 중이라는 뜻, "for sale"은 판매 중이라는 뜻이에요.', 'B1', 'shopping', 2, 'discount sale promotion shopping', 3),
('nuc_shopping_04', 'refund', 'exchange', NULL, '환불', '교환', NULL, 'refund는 돈을 돌려받는 것, exchange는 다른 상품으로 교환하는 것이에요.', 'I''d like a refund for this product.', 'Can I exchange this for a different size?', NULL, '매장 정책에 따라 환불(refund)이 안 될 수도 있으니 exchange를 먼저 물어볼 수 있어요.', 'B1', 'shopping', 2, 'refund exchange return policy', 4),
('nuc_shopping_05', 'price', 'cost', 'fee', '가격', '비용', '수수료 / 요금', 'price는 상품의 표시 가격, cost는 총 드는 비용, fee는 서비스·전문직에 대한 요금이에요.', 'What''s the price of this dress?', 'The total cost including tax is high.', 'There is a service fee for delivery.', 'price는 물건, fee는 서비스, cost는 포괄적 비용에 써요.', 'B2', 'shopping', 1, 'price cost fee payment', 5),
('nuc_shopping_06', 'bargain', 'negotiate', NULL, '흥정하다 / 싸게 산 것', '협상하다', NULL, 'bargain은 싸게 잘 샀다는 의미나 흥정 행위, negotiate는 공식적으로 조건을 협상하는 것이에요.', 'That coat was a real bargain!', 'You can negotiate the price at the market.', NULL, '재래시장에서는 bargain, 비즈니스·계약에서는 negotiate가 자연스러워요.', 'B2', 'shopping', 2, 'bargain negotiate price market', 6),
('nuc_shopping_07', 'receipt', 'invoice', NULL, '영수증 (소비자용)', '청구서 (사업용)', NULL, 'receipt는 결제 후 받는 영수증, invoice는 대금 청구를 위한 공식 청구서예요.', 'Keep your receipt for a possible return.', 'The vendor sent us an invoice for the order.', NULL, 'invoice는 B2B 거래에서, receipt는 소비자 쇼핑에서 써요.', 'B2', 'shopping', 1, 'receipt invoice payment document', 7),
('nuc_shopping_08', 'browse', 'search', NULL, '둘러보다', '검색하다', NULL, 'browse는 특정 목적 없이 구경하는 것, search는 원하는 것을 찾아 탐색하는 것이에요.', 'I was just browsing the store.', 'I searched online for the best deal.', NULL, '"Just browsing"은 "그냥 구경 중이에요"라는 표현으로 점원에게 자주 써요.', 'B2', 'shopping', 2, 'browse search online shopping', 8),
('nuc_shopping_09', 'wholesale', 'retail', NULL, '도매', '소매', NULL, 'wholesale은 대량으로 싸게 사는 도매, retail은 소비자에게 파는 소매예요.', 'He buys goods wholesale and resells them.', 'The retail price is twice the wholesale price.', NULL, 'retail price(소비자가)는 wholesale price(도매가)보다 비싼 게 일반적이에요.', 'B2', 'shopping', 1, 'wholesale retail price trade', 9),
('nuc_shopping_10', 'counterfeit', 'fake', NULL, '위조품', '가짜', NULL, 'fake는 진짜가 아닌 모든 것, counterfeit는 특히 상표·화폐를 불법으로 위조한 것이에요.', 'Police seized counterfeit designer bags.', 'That smile looks fake.', NULL, 'counterfeit는 법적·공식 맥락, fake는 일상 구어에서 써요.', 'C1', 'shopping', 1, 'counterfeit fake brand luxury', 10),
('nuc_shopping_11', 'impulse', 'spontaneous', NULL, '충동 (소비)', '자발적인', NULL, 'impulse buying은 계획 없이 충동적으로 구매하는 것, spontaneous는 즉흥적이지만 부정적 뉘앙스가 없어요.', 'She made an impulse purchase at the checkout.', 'It was a spontaneous decision to go shopping.', NULL, 'impulse는 쇼핑에서 부정적 뉘앙스, spontaneous는 즉흥적이지만 긍정적 느낌이에요.', 'C1', 'shopping', 2, 'impulse buying spontaneous decision', 11),
('nuc_shopping_12', 'frugal', 'stingy', NULL, '검소한', '인색한', NULL, 'frugal은 절약하는 긍정적 태도, stingy는 지나치게 아끼는 부정적 표현이에요.', 'She''s frugal and saves half her income.', 'He''s so stingy he never buys lunch for others.', NULL, 'frugal은 칭찬, stingy는 비판이에요 — 뉘앙스 차이가 커요.', 'C1', 'shopping', 2, 'frugal stingy saving money', 12),
('nuc_shopping_13', 'consumer', 'customer', NULL, '소비자 (경제 주체)', '고객 (특정 가게)', NULL, 'customer는 특정 가게·서비스를 이용하는 사람, consumer는 경제적 의미의 소비 주체예요.', 'Consumer spending rose last quarter.', 'The customer asked for a refund.', NULL, 'consumer rights(소비자 권리), customer service(고객 서비스)처럼 각각 관용 표현이 있어요.', 'C2', 'shopping', 1, 'consumer customer retail economics', 13);
INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_cafe_01', 'drink', 'beverage', NULL, '마시다 / 음료 (일상)', '음료 (격식)', NULL, 'drink는 일상 구어, beverage는 격식·메뉴판·상업용 표현이에요.', 'What would you like to drink?', 'Our beverages include coffee, tea, and juice.', NULL, '메뉴판·광고에서 beverage, 일상 주문에서 drink가 자연스러워요.', 'B1', 'cafe', 1, 'coffee drinks beverages cafe menu', 1),
('nuc_cafe_02', 'strong', 'bold', NULL, '진한 (커피)', '풍미 강한 (커피)', NULL, 'strong coffee는 카페인이나 농도가 진한 커피, bold는 풍부하고 묵직한 맛을 강조해요.', 'I need a strong coffee to wake up.', 'This blend has a bold, smoky flavor.', NULL, '카페 메뉴에서 bold는 맛 설명, strong은 농도를 가리켜요.', 'B1', 'cafe', 2, 'coffee strong bold flavor espresso', 2),
('nuc_cafe_03', 'order', 'ask for', NULL, '주문하다', '요청하다', NULL, 'order는 공식적으로 음식이나 음료를 주문하는 것, ask for는 무언가를 부탁하거나 요청하는 것이에요.', 'I''d like to order a latte, please.', 'Can I ask for an extra napkin?', NULL, 'order는 카운터·종업원에게, ask for는 추가 요청이나 부탁에 써요.', 'B1', 'cafe', 1, 'order coffee cafe counter', 3),
('nuc_cafe_04', 'takeaway', 'to go', NULL, '포장 (영국식)', '포장 (미국식)', NULL, '"takeaway"는 영국 영어, "to go"는 미국 영어로 포장 주문을 뜻해요.', 'One coffee, takeaway please.', 'Can I get that to go?', NULL, '한국 스타벅스는 "for here or to go?"라는 미국식 표현을 써요.', 'B1', 'cafe', 2, 'takeaway to go coffee cup', 4),
('nuc_cafe_05', 'hot', 'iced', NULL, '따뜻한', '아이스', NULL, 'hot과 iced는 음료 온도를 나타내는 기본 구분이에요. 영어 카페에서는 hot / iced로 구분해요.', 'I''ll have a hot Americano, please.', 'Give me an iced latte.', NULL, '미국·영국 카페에서는 "hot" 또는 "iced"로 명확하게 말해야 해요.', 'B1', 'cafe', 2, 'hot iced coffee temperature drink', 5),
('nuc_cafe_06', 'bitter', 'sour', NULL, '쓴', '신', NULL, 'bitter는 커피·다크초콜릿의 쓴맛, sour는 식초·레몬처럼 신맛이에요.', 'This espresso is too bitter for me.', 'The cold brew tastes slightly sour.', NULL, '과추출(over-extracted) 커피는 bitter, 미추출(under-extracted)은 sour해져요.', 'B2', 'cafe', 1, 'bitter sour taste coffee flavor', 6),
('nuc_cafe_07', 'decaf', 'caffeine-free', NULL, '디카페인 (카페인 제거)', '무카페인 (원래 없음)', NULL, 'decaf는 원래 카페인이 있는 음료에서 제거한 것, caffeine-free는 처음부터 카페인이 없는 음료예요.', 'Do you have decaf espresso?', 'Herbal tea is naturally caffeine-free.', NULL, '카페인 걱정이 있다면 decaf coffee vs caffeine-free tea를 구분해 주문해요.', 'B2', 'cafe', 2, 'decaf caffeine coffee tea health', 7),
('nuc_cafe_08', 'espresso', 'americano', NULL, '에스프레소', '아메리카노', NULL, 'espresso는 압력으로 뽑은 진한 원액, Americano는 에스프레소에 물을 희석한 음료예요.', 'A double espresso, please.', 'I''ll have an Americano with an extra shot.', NULL, 'Americano는 에스프레소의 진한 맛에 물을 더해 마시기 편하게 한 것이에요.', 'B2', 'cafe', 1, 'espresso americano coffee shot', 8),
('nuc_cafe_09', 'aroma', 'flavor', NULL, '향', '맛', NULL, 'aroma는 코로 느끼는 향기, flavor는 입으로 느끼는 맛이에요. 커피 평가에서 둘 다 중요해요.', 'The aroma of freshly brewed coffee is wonderful.', 'This blend has a chocolatey flavor.', NULL, 'aroma는 후각, flavor는 미각이에요 — 커피 리뷰에서 함께 써요.', 'B2', 'cafe', 2, 'aroma flavor coffee sensory', 9),
('nuc_cafe_06b', 'cozy', 'comfortable', NULL, '아늑한', '편안한', NULL, 'cozy는 작고 따뜻하며 아늑한 분위기, comfortable은 넓게 편안한 상태를 뜻해요.', 'This cafe has a cozy atmosphere.', 'The chairs here are very comfortable.', NULL, 'cozy는 분위기, comfortable은 물리적 편안함을 강조해요.', 'B2', 'cafe', 2, 'cozy comfortable cafe atmosphere', 10),
('nuc_cafe_11', 'artisan', 'specialty', NULL, '장인 (수제)', '스페셜티 (고품질)', NULL, 'artisan은 장인이 손으로 만든 것, specialty는 특별히 엄선된 고품질을 뜻해요.', 'This artisan bakery makes bread by hand.', 'We only serve specialty coffee here.', NULL, 'specialty coffee는 국제 기준(SCA) 80점 이상의 고품질 원두를 가리켜요.', 'C1', 'cafe', 1, 'artisan specialty coffee bread craft', 11),
('nuc_cafe_12', 'ambient', 'atmosphere', NULL, '주변 환경 (음악·조명)', '분위기 (전체)', NULL, 'ambient는 배경 소리·빛 등 환경 요소, atmosphere는 장소 전체의 분위기를 뜻해요.', 'The cafe has soft ambient music.', 'The atmosphere in this place is very relaxed.', NULL, 'ambient music은 배경음악, atmosphere는 카페 전체 느낌을 표현해요.', 'C1', 'cafe', 2, 'ambient atmosphere cafe music lighting', 12),
('nuc_cafe_13', 'connoisseur', 'enthusiast', NULL, '전문 감식가', '열정 애호가', NULL, 'connoisseur는 전문적 감식 능력을 갖춘 사람, enthusiast는 단순히 매우 좋아하는 사람이에요.', 'She''s a coffee connoisseur who can identify the origin by taste.', 'He''s a coffee enthusiast who visits new cafes every week.', NULL, 'connoisseur는 전문성 강조, enthusiast는 열정 강조예요.', 'C2', 'cafe', 1, 'connoisseur enthusiast coffee expert', 13);
INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_transport_01', 'ride', 'drive', NULL, '(타다) 승객으로', '운전하다', NULL, 'ride는 버스·택시 등을 타는 것(승객), drive는 직접 운전하는 것이에요.', 'I''ll take a ride to the station.', 'She drives to work every day.', NULL, 'ride a bus/taxi (타다), drive a car (운전하다)처럼 구분해요.', 'B1', 'transport', 1, 'ride drive car bus transport', 1),
('nuc_transport_02', 'on time', 'in time', NULL, '정시에', '시간 안에', NULL, '"on time"은 약속된 시간에 정확히, "in time"은 마감 시간 내에 (여유 있게) 도착하는 것이에요.', 'The train arrived on time.', 'We got there just in time to board.', NULL, '"on time" = 정시 도착, "in time" = 늦지 않게 도착 (차이 기억!))', 'B1', 'transport', 1, 'on time in time schedule transport', 2),
('nuc_transport_03', 'ticket', 'pass', NULL, '표 (1회용)', '패스 (정기·다회)', NULL, 'ticket은 1회 또는 특정 승차용, pass는 기간·횟수 무제한 이용권이에요.', 'I bought a one-way ticket to Busan.', 'I use a monthly bus pass.', NULL, 'single ticket(1회권), return ticket(왕복권), season pass(정기권)을 구분해요.', 'B1', 'transport', 2, 'ticket pass transit bus train', 3),
('nuc_transport_04', 'delay', 'cancel', NULL, '지연', '취소', NULL, 'delay는 예정 시간보다 늦는 것, cancel은 완전히 취소하는 것이에요.', 'The flight was delayed by two hours.', 'The service was cancelled due to the storm.', NULL, '공항에서 delayed와 cancelled를 모니터로 꼭 확인해야 해요.', 'B1', 'transport', 2, 'delay cancel flight train schedule', 4),
('nuc_transport_05', 'fare', 'toll', NULL, '운임 (교통)', '통행료 (도로)', NULL, 'fare는 버스·지하철·택시 요금, toll은 고속도로·교량 통행료예요.', 'The bus fare is 1,500 won.', 'There''s a toll on this highway.', NULL, 'fare는 대중교통, toll은 도로 이용요금에 써요.', 'B2', 'transport', 1, 'fare toll transportation fee road', 5),
('nuc_transport_06', 'transfer', 'transit', NULL, '환승하다', '통과 / 경유', NULL, 'transfer는 다른 노선·교통수단으로 갈아타는 것, transit는 목적지로 가는 중간 경유를 뜻해요.', 'Transfer to Line 2 at Hongik station.', 'We have a two-hour transit in Singapore.', NULL, 'in transit는 경유 중이라는 뜻, transit visa는 경유 비자예요.', 'B2', 'transport', 1, 'transfer transit connection hub', 6),
('nuc_transport_07', 'board', 'embark', NULL, '탑승하다 (일반)', '탑승하다 (격식)', NULL, 'board는 일상적으로 비행기·배·버스에 탑승하는 것, embark는 좀 더 격식 있거나 항해 시작 뉘앙스예요.', 'Passengers, please board through gate 3.', 'The ship was about to embark on a long voyage.', NULL, '공항 안내방송에서는 board, 문학·격식 글에서는 embark를 자주 써요.', 'B2', 'transport', 2, 'board embark flight ship departure', 7),
('nuc_transport_08', 'traffic', 'congestion', NULL, '교통 (흐름)', '교통 체증', NULL, 'traffic은 도로의 차량 흐름 전반, congestion은 막혀서 정체된 상태를 뜻해요.', 'The traffic was heavy this morning.', 'Road congestion caused a two-hour delay.', NULL, 'traffic jam / heavy traffic / congestion 모두 막힌 교통을 뜻해요.', 'B2', 'transport', 2, 'traffic congestion road delay', 8),
('nuc_transport_09', 'commute', 'travel', NULL, '통근하다', '여행하다', NULL, 'commute는 매일 집과 직장을 오가는 것, travel은 목적지로 이동하는 더 넓은 개념이에요.', 'She commutes two hours each way.', 'He travels to different countries for work.', NULL, 'commute는 반복적 일상 이동, travel은 새로운 장소로의 이동이에요.', 'B2', 'transport', 1, 'commute travel daily work journey', 9),
('nuc_transport_10', 'detour', 'shortcut', NULL, '우회로', '지름길', NULL, 'detour는 원래 경로를 피해 돌아가는 길, shortcut은 더 빨리 가는 지름길이에요.', 'We took a detour due to road works.', 'I know a shortcut through the park.', NULL, 'detour는 어쩔 수 없이 돌아가는 것, shortcut은 의도적으로 빠르게 가는 것이에요.', 'B2', 'transport', 2, 'detour shortcut route road', 10),
('nuc_transport_11', 'itinerary', 'schedule', NULL, '여행 일정표', '일정 / 스케줄', NULL, 'itinerary는 여행 경로와 일정이 담긴 계획서, schedule은 더 넓은 일정표예요.', 'The tour operator sent us a detailed itinerary.', 'What''s the bus schedule on Sundays?', NULL, 'itinerary는 여행에 특화된 표현, schedule은 모든 종류의 일정에 써요.', 'C1', 'transport', 1, 'itinerary schedule travel plan', 11),
('nuc_transport_12', 'hail', 'flag down', NULL, '(택시를) 손짓으로 부르다', '(차를) 손을 흔들어 세우다', NULL, '"hail a cab"은 도로에서 택시를 부르는 표현, "flag down"은 손을 흔들어 차를 세우는 표현이에요.', 'She tried to hail a taxi in the rain.', 'He flagged down a passing bus.', NULL, '"hail a cab"은 뉴욕 영어에서 특히 자주 쓰여요.', 'C1', 'transport', 2, 'taxi hail flag street transport', 12),
('nuc_transport_13', 'infrastructure', 'logistics', NULL, '(교통) 인프라', '물류', NULL, 'infrastructure는 도로·철도 등 기반 시설, logistics는 사람과 화물의 이동 계획·관리예요.', 'The country is investing in transport infrastructure.', 'Efficient logistics reduced delivery times.', NULL, 'infrastructure는 하드웨어(시설), logistics는 소프트웨어(운영·계획)에 가까워요.', 'C2', 'transport', 1, 'infrastructure logistics transport network', 13);
INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, tip, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('nuc_health_01', 'sick', 'ill', NULL, '아픈 (일상)', '아픈 (격식)', NULL, 'sick은 미국식 일상 표현, ill은 영국식 또는 격식 표현이에요. 둘 다 몸이 아프다는 뜻이에요.', 'I feel sick today.', 'She was seriously ill in hospital.', NULL, 'sick은 미국, ill은 영국에서 선호해요. ill이 좀 더 심각한 뉘앙스이기도 해요.', 'B1', 'health', 1, 'sick ill health medical', 1),
('nuc_health_02', 'pain', 'ache', NULL, '통증 (갑작스럽고 강한)', '통증 (지속적이고 은은한)', NULL, 'pain은 급성이거나 강한 통증, ache는 두통이나 근육통처럼 지속적으로 은은하게 아픈 것이에요.', 'I felt a sharp pain in my chest.', 'I have a headache and a backache.', NULL, 'toothache, headache, stomachache처럼 -ache는 특정 부위 통증에 붙여요.', 'B1', 'health', 1, 'pain ache symptom body', 2),
('nuc_health_03', 'symptom', 'sign', NULL, '증상', '징후', NULL, 'symptom은 환자가 느끼는 주관적 증상, sign은 의사가 관찰하는 객관적 징후예요.', 'Common symptoms include fever and fatigue.', 'Swollen lymph nodes are a sign of infection.', NULL, 'symptom(증상)은 환자 관점, sign(징후)은 의사 관점이에요.', 'B1', 'health', 2, 'symptom sign medical health', 3),
('nuc_health_04', 'cure', 'treat', NULL, '완치하다', '치료하다', NULL, 'treat는 증상을 다스리는 치료, cure는 병을 완전히 고치는 완치예요.', 'There is no known cure for this disease.', 'The doctor treated my infection with antibiotics.', NULL, 'treat는 과정, cure는 결과(완치)를 강조해요.', 'B2', 'health', 1, 'cure treat medicine hospital', 4),
('nuc_health_05', 'physician', 'doctor', NULL, '내과 의사 (격식)', '의사 (일반)', NULL, 'doctor는 일반적인 의사, physician은 특히 내과 전문의를 가리켜요.', 'Consult a physician before taking this medication.', 'My doctor advised me to rest.', NULL, 'physician assistant(PA)는 의사 보조사를 뜻하는 직함이에요.', 'B2', 'health', 2, 'physician doctor medical professional', 5),
('nuc_health_06', 'diet', 'nutrition', NULL, '식단 / 다이어트', '영양', NULL, 'diet는 특정 목적을 위한 식단 또는 식습관, nutrition은 음식의 영양소와 건강 관계를 뜻해요.', 'She''s on a low-carb diet.', 'Good nutrition is essential for children.', NULL, 'diet는 뭘 먹느냐(선택), nutrition은 영양 성분·과학을 가리켜요.', 'B2', 'health', 1, 'diet nutrition food health', 6),
('nuc_health_07', 'allergy', 'intolerance', NULL, '알레르기 (면역 반응)', '불내성 (소화 문제)', NULL, 'allergy는 면역계가 반응하는 것, intolerance는 소화 시스템이 특정 식품을 처리 못 하는 것이에요.', 'She has a severe nut allergy.', 'He has lactose intolerance.', NULL, '알레르기는 생명을 위협할 수 있어요. intolerance는 덜 심각하지만 불편해요.', 'B2', 'health', 2, 'allergy intolerance food health', 7),
('nuc_health_08', 'pharmacy', 'drugstore', NULL, '약국 (약 중심)', '드럭스토어 (잡화 포함)', NULL, 'pharmacy는 처방전 약을 조제하는 약국, drugstore는 약 외에도 화장품·잡화를 파는 곳이에요.', 'Pick up the prescription at the pharmacy.', 'I got some cold medicine at the drugstore.', NULL, 'pharmacist는 약사, drugstore는 미국식 표현이에요.', 'B2', 'health', 1, 'pharmacy drugstore medicine prescription', 8),
('nuc_health_09', 'chronic', 'acute', NULL, '만성적인', '급성의', NULL, 'chronic은 장기간 지속되는 만성 상태, acute는 갑자기 심하게 나타나는 급성 상태예요.', 'He suffers from chronic back pain.', 'She was admitted for acute appendicitis.', NULL, 'chronic(만성) vs acute(급성)는 의료 문서·뉴스에서 자주 나와요.', 'C1', 'health', 1, 'chronic acute medical condition', 9),
('nuc_health_10', 'epidemic', 'pandemic', NULL, '유행병 (지역)', '팬데믹 (전세계)', NULL, 'epidemic은 특정 지역·집단에서 빠르게 퍼지는 것, pandemic은 전 세계적으로 퍼진 것이에요.', 'There was a flu epidemic in the region.', 'COVID-19 became a global pandemic.', NULL, 'pandemic > epidemic > endemic(풍토병) 순으로 확산 범위가 달라요.', 'C1', 'health', 1, 'epidemic pandemic disease spread', 10),
('nuc_health_11', 'diagnosis', 'prognosis', NULL, '진단', '예후', NULL, 'diagnosis는 병명을 찾는 진단, prognosis는 병의 경과·결과를 예측하는 예후예요.', 'The diagnosis was Type 2 diabetes.', 'The prognosis for early-stage cancer is good.', NULL, 'diagnosis는 현재(뭔 병?), prognosis는 미래(어떻게 될까?)를 가리켜요.', 'C1', 'health', 2, 'diagnosis prognosis medical outcome', 11),
('nuc_health_12', 'placebo', 'nocebo', NULL, '위약 효과 (긍정)', '노시보 효과 (부정)', NULL, 'placebo effect는 가짜 약을 진짜로 믿어 증상이 나아지는 것, nocebo는 반대로 나빠지는 것이에요.', 'The placebo reduced pain in half the patients.', 'The nocebo effect caused side effects even with sugar pills.', NULL, 'placebo는 긍정적 심리 효과, nocebo는 부정적 심리 효과예요.', 'C2', 'health', 1, 'placebo nocebo psychology medicine', 12),
('nuc_health_13', 'rehabilitation', 'recovery', NULL, '재활', '회복', NULL, 'recovery는 건강이 돌아오는 과정 전반, rehabilitation은 기능 회복을 위한 체계적 프로그램이에요.', 'The athlete''s rehabilitation took six months.', 'She made a full recovery after surgery.', NULL, 'rehabilitation(재활)은 물리치료·전문 프로그램, recovery(회복)는 더 넓은 개념이에요.', 'C2', 'health', 2, 'rehabilitation recovery therapy physical', 13);
